css:
a:link, a:active { color: rgb(102, 0, 153); }
a:visited { color: rgb(153, 51, 153); }
a:link.newsalert, a:active.newsalert, a:visited.newsalert { font-size: 12px; color: rgb(255, 0, 0); }
a:link.white, a:active.white, a:visited.white { color: rgb(255, 255, 255); }
body { font-family: Arial, Helvetica, Verdana, sans-serif; font-size: 12px; background-color: rgb(255, 255, 255); color: rgb(0, 0, 0); }
h1, h2, h3, h4, h5, h6 { font-family: Arial, Helvetica, Verdana, sans-serif; margin-top: 0px; margin-bottom: 0px; font-weight: normal; }
div, p, .content { font-family: Arial, Helvetica, Verdana, sans-serif; font-size: 12px; color: rgb(0, 0, 0); }
form { padding: 0px; margin: 0px; }
hr { height: 1px; width: 100%; clear: both; }
ol { margin-top: 0px; margin-bottom: 0px; }
ol li { margin-left: -8px; }
table { margin-left: 0px; margin-top: 0px; padding: 0px; color: rgb(0, 0, 0); }
td { font-family: Arial, Helvetica, Verdana, sans-serif; font-size: 12px; }
tr.resultsgray { height: 30px; font-size: 11px; background-color: rgb(230, 230, 230); }
tr.resultswhite { height: 30px; font-size: 11px; background-color: rgb(255, 255, 255); }
tr.resultsgraysmall { height: 15px; font-size: 11px; background-color: rgb(230, 230, 230); }
tr.resultswhitesmall { height: 15px; font-size: 11px; background-color: rgb(255, 255, 255); }
ul { margin-top: 0px; margin-bottom: 0px; }
.afooternav { font-size: 11px; color: rgb(102, 0, 153); }
.autilitynav { font-size: 11px; color: rgb(102, 0, 153); }
.articleheader { font-size: 12px; color: rgb(102, 0, 153); }
.buttongray { font-size: 12px; }
.buttonpurple { font-size: 12px; background-color: rgb(102, 0, 153); color: rgb(255, 255, 255); }
.error { font-size: 12px; color: rgb(255, 0, 0); font-weight: 600; }
.footertext { font-size: 11px; color: rgb(0, 0, 0); }
.formtext { font-family: Arial, helvetica, Verdana, sans-serif; font-size: 12px; color: rgb(0, 0, 0); }
.mainheader1 { font-size: 18px; color: rgb(102, 0, 153); font-weight: normal; }
.mainheader2 { font-size: 14px; color: rgb(153, 153, 153); font-weight: normal; }
.nnform { font-family: "Courier New", Courier, monospace; font-size: 11px; padding: 0px; margin: 0px; }
.phonenumber { color: rgb(102, 0, 153); font-weight: bold; }
.resultstableheader { color: rgb(255, 255, 255); font-family: Arial, Helvetica, Verdana, sans-serif; font-size: 11px; font-weight: bold; }
.resultstable { color: rgb(0, 0, 0); font-family: Arial, Helvetica, Verdana, sans-serif; font-size: 11px; }
.resultstablegray { background: rgb(204, 204, 204); color: rgb(0, 0, 0); font-family: Arial, Helvetica, Verdana, sans-serif; font-size: 11px; }
.sidenav { font-size: 11px; }
.small { font-size: 11px; }
.stepsoff { font-size: 12px; color: rgb(153, 153, 153); font-weight: 600; }
.stepson { font-size: 12px; color: rgb(255, 255, 255); font-weight: 600; }
.subheader1 { font-size: 12px; color: rgb(102, 0, 153); font-weight: 600; }
.subheader2 { font-size: 11px; color: rgb(102, 0, 153); font-weight: 600; }
.subheaderblack1 { font-size: 12px; color: rgb(0, 0, 0); font-weight: 600; }
.subheaderwhite1 { font-size: 12px; color: rgb(255, 255, 255); font-weight: 600; }
